  1	import { type FC, useEffect, useReducer } from 'react';
  2	import { useForkliftTranslation } from 'src/utils/i18n';
  3	
  4	import LoadingSuspend from '@components/LoadingSuspend';
  5	import {
  6	  ProviderModelGroupVersionKind,
  7	  StorageMapModel,
  8	  type V1beta1Provider,
  9	  type V1beta1StorageMap,
 10	} from '@kubev2v/types';
 11	import { k8sUpdate, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 12	import {
 13	  Button,
 14	  ButtonVariant,
 15	  DescriptionList,
 16	  Flex,
 17	  FlexItem,
 18	  Spinner,
 19	} from '@patternfly/react-core';
 20	
 21	import { ProvidersEdit } from './components/ProvidersEdit';
 22	import { providersSectionReducer, type ProvidersSectionState } from './state/reducer';
 23	
 24	const initialState: ProvidersSectionState = {
 25	  hasChanges: false,
 26	  sourceProviderMode: 'view',
 27	  targetProviderMode: 'view',
 28	  updating: false,
 29	};
 30	
 31	export const ProvidersSection: FC<ProvidersSectionProps> = ({ obj }) => {
 32	  const { t } = useForkliftTranslation();
 33	  const [state, dispatch] = useReducer(providersSectionReducer, initialState);
 34	
 35	  // Initialize the state with the prop obj
 36	  useEffect(() => {
 37	    dispatch({ payload: obj, type: 'INIT' });
 38	  }, [obj]);
 39	
 40	  const [providers, providersLoaded, providersLoadError] = useK8sWatchResource<V1beta1Provider[]>({
 41	    groupVersionKind: ProviderModelGroupVersionKind,
 42	    isList: true,
 43	    namespace: obj.metadata?.namespace,
 44	    namespaced: true,
 45	  });
 46	
 47	  const targetProviders = providers.filter(
 48	    (provider) => provider?.spec?.type && ['openshift'].includes(provider?.spec?.type),
 49	  );
 50	
 51	  const onUpdate = async () => {
 52	    if (state.StorageMap) {
 53	      dispatch({ payload: true, type: 'SET_UPDATING' });
 54	      await k8sUpdate({ data: state.StorageMap, model: StorageMapModel });
 55	    }
 56	  };
 57	
 58	  const onClick = () => {
 59	    dispatch({ payload: obj, type: 'INIT' });
 60	  };
 61	
 62	  const onChangeSource: (value: string) => void = (value) => {
 63	    const payload = providers.find((provider) => provider?.metadata?.name === value);
 64	    if (payload) {
 65	      dispatch({ payload, type: 'SET_SOURCE_PROVIDER' });
 66	    }
 67	  };
 68	
 69	  const onChangeTarget: (value: string) => void = (value) => {
 70	    const payload = providers.find((provider) => provider?.metadata?.name === value);
 71	    if (payload) {
 72	      dispatch({ payload, type: 'SET_TARGET_PROVIDER' });
 73	    }
 74	  };
 75	
 76	  return (
 77	    <LoadingSuspend obj={providers} loaded={providersLoaded} loadError={providersLoadError}>
 78	      <Flex className="forklift-network-map__details-tab--update-button">
 79	        <FlexItem>
 80	          <Button
 81	            variant={ButtonVariant.primary}
 82	            onClick={onUpdate}
 83	            isDisabled={!state.hasChanges || state.updating}
 84	            icon={state.updating ? <Spinner size="sm" /> : undefined}
 85	          >
 86	            {t('Update providers')}
 87	          </Button>
 88	        </FlexItem>
 89	
 90	        <FlexItem>
 91	          <Button
 92	            variant={ButtonVariant.secondary}
 93	            onClick={onClick}
 94	            isDisabled={!state.hasChanges || state.updating}
 95	          >
 96	            {t('Cancel')}
 97	          </Button>
 98	        </FlexItem>
 99	      </Flex>
100	
101	      <DescriptionList
102	        className="pf-v6-u-mt-md"
103	        columnModifier={{
104	          default: '1Col',
105	        }}
106	      >
107	        <ProvidersEdit
108	          providers={providers}
109	          selectedProviderName={state.StorageMap?.spec?.provider?.source?.name ?? ''}
110	          label={t('Source provider')}
111	          placeHolderLabel={t('Select a provider')}
112	          onChange={onChangeSource}
113	          invalidLabel={t('The chosen provider is no longer available.')}
114	          mode={state.sourceProviderMode ?? 'view'}
115	          helpContent="source provider"
116	          setMode={() => {
117	            dispatch({ payload: 'edit', type: 'SET_SOURCE_PROVIDER_MODE' });
118	          }}
119	        />
120	
121	        <ProvidersEdit
122	          providers={targetProviders}
123	          selectedProviderName={state.StorageMap?.spec?.provider?.destination?.name ?? ''}
124	          label={t('Target provider')}
125	          placeHolderLabel={t('Select a provider')}
126	          onChange={onChangeTarget}
127	          invalidLabel={t('The chosen provider is no longer available.')}
128	          mode={state.targetProviderMode ?? 'view'}
129	          helpContent="Target provider"
130	          setMode={() => {
131	            dispatch({ payload: 'edit', type: 'SET_TARGET_PROVIDER_MODE' });
132	          }}
133	        />
134	      </DescriptionList>
135	    </LoadingSuspend>
136	  );
137	};
138	
139	type ProvidersSectionProps = {
140	  obj: V1beta1StorageMap;
141	};

